"use client";

import { useState } from "react";
import { ShoppingCart } from "lucide-react";
import { addToCart } from "@/lib/cart";
import { Product } from "@/lib/products";
import { getCustomerToken } from "@/lib/wishlist";

export default function AddToCartButton({
  product,
  className = "ig-add-cart-btn",
  label,
}: {
  product: Product;
  className?: string;
  label?: string;
}) {
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const defaultVariant = product.variants?.find((variant) => variant.isDefault) || product.variants?.[0];

  const onClick = async () => {
    if (!getCustomerToken()) {
      window.location.href = "/login";
      return;
    }

    try {
      setLoading(true);
      setMessage("");
      await addToCart(product.id, defaultVariant?.id);
      setMessage("Added");
      window.dispatchEvent(new Event("cart:updated"));
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : "";
      if (errorMessage === "LOGIN_REQUIRED") {
        window.location.href = "/login";
        return;
      }

      if (/select|flavour|size/i.test(errorMessage)) {
        window.location.href = `/product/${product.slug}`;
        return;
      }

      setMessage(errorMessage || "Could not add");
    } finally {
      setLoading(false);
      window.setTimeout(() => setMessage(""), 1800);
    }
  };

  return (
    <button
      type="button"
      className={className}
      onClick={onClick}
      disabled={loading}
      aria-label={`Add ${product.title} to cart`}
      title={message || "Add to cart"}
    >
      {label ? <span>{loading ? "Adding..." : message || label}</span> : <ShoppingCart size={18} />}
    </button>
  );
}
